1	syntax = "proto3";
2	
3	package ans;
4	
5	// ────────────────────────────────────────────────────────────
6	// Agent Nervous System — Complete gRPC Service Definition
7	// Version: 1.0.0 (Phase 0 — Protocols Frozen)
8	// ────────────────────────────────────────────────────────────
9	
10	service AgentNervousSystem {
11	  // ── Session Management ──────────────────────────────────
12	  rpc CreateSession(CreateSessionRequest) returns (Session);
13	  rpc CloseSession(CloseSessionRequest) returns (Empty);
14	  rpc Navigate(NavigateRequest) returns (PageState);
15	  rpc ExecuteAction(ExecuteActionRequest) returns (ActionResult);
16	
17	  // ── Perception ──────────────────────────────────────────
18	  rpc GetDistilledDom(DomRequest) returns (DistilledDom);
19	  rpc CaptureScreenshot(ScreenshotRequest) returns (ScreenshotResponse);
20	  rpc ComputeDiff(DiffRequest) returns (DiffReport);
21	
22	  // ── Goal State ──────────────────────────────────────────
23	  rpc CreateGoal(CreateGoalRequest) returns (GoalState);
24	  rpc GetGoalState(GoalStateRequest) returns (GoalState);
25	  rpc UpdateGoalProgress(ProgressUpdate) returns (GoalState);
26	  rpc SubscribeGoalUpdates(GoalStateRequest) returns (stream GoalUpdate);
27	
28	  // ── Eye Reports (Streaming) ─────────────────────────────
29	  rpc SubmitEyeReports(SubmitReportsRequest) returns (RoutedSignal);
30	  rpc SubscribeEyeReports(SessionRequest) returns (stream EyeReport);
31	
32	  // ── Immune System ───────────────────────────────────────
33	  rpc ClassifyDistractions(DistractionRequest) returns (DistractionList);
34	  rpc ScanInjections(InjectionScanRequest) returns (InjectionScanResult);
35	  rpc CheckAction(ActionCheckRequest) returns (ActionCheckResponse);
36	
37	  // ── Decision Intelligence ───────────────────────────────
38	  rpc StoreScore(StoreScoreRequest) returns (StoreScoreResponse);
39	  rpc QueryBestActions(QueryBestActionsRequest) returns (ScoredActionList);
40	  rpc SearchSimilarDecisions(SearchRequest) returns (ScoredActionList);
41	
42	  // ── Budget ──────────────────────────────────────────────
43	  rpc GetBudgetStatus(BudgetStatusRequest) returns (BudgetStatus);
44	  rpc ConfigureBudget(BudgetConfigRequest) returns (BudgetConfig);
45	
46	  // ── Health ──────────────────────────────────────────────
47	  rpc Health(Empty) returns (HealthStatus);
48	}
49	
50	// ────────────────────────────────────────────────────────────
51	// Common Types
52	// ────────────────────────────────────────────────────────────
53	
54	message Empty {}
55	
56	message SessionRequest {
57	  string session_id = 1;
58	}
59	
60	// ────────────────────────────────────────────────────────────
61	// Session Management
62	// ────────────────────────────────────────────────────────────
63	
64	message CreateSessionRequest {
65	  string goal_id = 1;
66	  string start_url = 2;
67	  map<string, string> headers = 3;
68	}
69	
70	message CloseSessionRequest {
71	  string session_id = 1;
72	  string reason = 2;
73	}
74	
75	message Session {
76	  string session_id = 1;
77	  string goal_id = 2;
78	  string status = 3;           // idle, navigating, executing, perceiving, blocked, failed
79	  PageState current_page = 4;
80	  int64 created_at = 5;
81	  int64 last_activity_at = 6;
82	}
83	
84	message NavigateRequest {
85	  string session_id = 1;
86	  string url = 2;
87	  int32 timeout_ms = 3;
88	}
89	
90	message PageState {
91	  string url = 1;
92	  string title = 2;
93	  bool loaded = 3;
94	  int64 dom_node_count = 4;
95	  repeated string visible_text = 5;
96	  int64 timestamp = 6;
97	}
98	
99	message BoundingBox {
100	  int32 x = 1;
101	  int32 y = 2;
102	  int32 width = 3;
103	  int32 height = 4;
104	}
105	
106	// ────────────────────────────────────────────────────────────
107	// Actions
108	// ────────────────────────────────────────────────────────────
109	
110	message ExecuteActionRequest {
111	  string session_id = 1;
112	  Action action = 2;
113	}
114	
115	message Action {
116	  string action_type = 1;      // click, type, scroll, select, navigate, wait, submit, screenshot
117	  string selector = 2;
118	  string value = 3;            // text to type, option to select, url to navigate
119	  map<string, string> params = 4;
120	}
121	
122	message ActionResult {
123	  bool success = 1;
124	  string error_message = 2;
125	  PageState new_state = 3;
126	  DiffReport diff = 4;
127	  int64 execution_time_ms = 5;
128	}
129	
130	message ActionCheckRequest {
131	  string session_id = 1;
132	  Action action = 2;
133	}
134	
135	message ActionCheckResponse {
136	  bool allowed = 1;
137	  string reason = 2;
138	  repeated string distraction_alerts = 3;
139	  repeated string injection_alerts = 4;
140	}
141	
142	// ────────────────────────────────────────────────────────────
143	// DOM Distillation
144	// ────────────────────────────────────────────────────────────
145	
146	message DomRequest {
147	  string session_id = 1;
148	  string mode = 2;             // text_only, input_fields, all_fields
149	}
150	
151	message DistilledDom {
152	  string mode = 1;
153	  string url = 2;
154	  string title = 3;
155	  repeated DistilledElement elements = 4;
156	  repeated InteractiveElement interactive = 5;
157	  repeated SemanticBlock semantic_blocks = 6;
158	  repeated DistractionFlag distraction_flags = 7;
159	  int64 timestamp = 8;
160	}
161	
162	message DistilledElement {
163	  string tag = 1;
164	  string text = 2;
165	  map<string, string> attributes = 3;
166	  string role = 4;
167	  bool is_visible = 5;
168	  BoundingBox bounding_box = 6;
169	  repeated int32 children = 7;
170	}
171	
172	message InteractiveElement {
173	  string selector = 1;
174	  string element_type = 2;     // button, input, select, textarea, link, checkbox, radio
175	  string label = 3;
176	  string placeholder = 4;
177	  string current_value = 5;
178	  bool is_visible = 6;
179	  bool is_enabled = 7;
180	  BoundingBox bounding_box = 8;
181	}
182	
183	message SemanticBlock {
184	  string block_type = 1;       // navigation, main_content, form, sidebar, footer, ad, cookie_banner
185	  string text_content = 2;
186	  repeated int32 element_indices = 3;
187	  float goal_relevance_score = 4;
188	}
189	
190	message DistractionFlag {
191	  string kind = 1;             // ad, popup, cookie_banner, newsletter_modal, redirect, autoplay_video, survey, notification
192	  string element_selector = 2;
193	  float confidence = 3;
194	  string suggested_action = 4; // dismiss, block, suppress, ignore, navigate_back
195	}
196	
197	// ────────────────────────────────────────────────────────────
198	// Screenshot
199	// ────────────────────────────────────────────────────────────
200	
201	message ScreenshotRequest {
202	  string session_id = 1;
203	  string format = 2;           // png, jpeg
204	  int32 quality = 3;           // 1-100, jpeg only
205	  bool full_page = 4;
206	  string arrow_shm_key = 5;    // key for Arrow IPC shared memory (bulk transfer)
207	}
208	
209	message ScreenshotResponse {
210	  bool success = 1;
211	  int64 size_bytes = 2;
212	  int32 width = 3;
213	  int32 height = 4;
214	  string format = 5;
215	  bytes data = 6;              // inline for small screenshots (<1MB), otherwise Arrow IPC
216	  string arrow_shm_key = 7;
217	}
218	
219	// ────────────────────────────────────────────────────────────
220	// Page Diff
221	// ────────────────────────────────────────────────────────────
222	
223	message DiffRequest {
224	  string session_id = 1;
225	  DistilledDom before = 2;
226	  DistilledDom after = 3;
227	}
228	
229	message DiffReport {
230	  string before_url = 1;
231	  string after_url = 2;
232	  bool is_same_page = 3;
233	  repeated ElementChange added = 4;
234	  repeated ElementChange removed = 5;
235	  repeated ElementModification modified = 6;
236	  float visual_diff_percentage = 7;
237	  string summary = 8;          // no_change, cosmetic_change, content_update, form_update, navigation, distraction_appeared, error_state
238	}
239	
240	message ElementChange {
241	  string tag = 1;
242	  string text = 2;
243	  string selector = 3;
244	  int32 index = 4;
245	}
246	
247	message ElementModification {
248	  string selector = 1;
249	  string attribute_name = 2;
250	  string old_value = 3;
251	  string new_value = 4;
252	}
253	
254	// ────────────────────────────────────────────────────────────
255	// Distraction Classification
256	// ────────────────────────────────────────────────────────────
257	
258	message DistractionRequest {
259	  string session_id = 1;
260	  string url = 2;
261	  DistilledDom dom = 3;
262	}
263	
264	message DistractionList {
265	  repeated Distraction distractions = 1;
266	  int64 classification_time_us = 2;
267	}
268	
269	message Distraction {
270	  string kind = 1;
271	  string element_selector = 2;
272	  float confidence = 3;
273	  string action = 4;           // dismiss, block, suppress, ignore, navigate_back
274	}
275	
276	// ────────────────────────────────────────────────────────────
277	// Prompt Injection Defense
278	// ────────────────────────────────────────────────────────────
279	
280	message InjectionScanRequest {
281	  string session_id = 1;
282	  string url = 2;
283	  string page_content = 3;     // raw HTML or distilled text
284	}
285	
286	message InjectionScanResult {
287	  float score = 1;             // 0.0 (safe) to 1.0 (definite injection)
288	  repeated FlaggedContent flagged = 2;
289	  string action = 3;           // allow, sanitize, block
290	  string reason = 4;
291	  int64 scan_time_us = 5;
292	}
293	
294	message FlaggedContent {
295	  string content_snippet = 1;
296	  string pattern_matched = 2;
297	  string location = 3;         // element attribute, hidden div, aria-label, css pseudo, etc.
298	  float confidence = 4;
299	}
300	
301	// ────────────────────────────────────────────────────────────
302	// Eye Reports
303	// ────────────────────────────────────────────────────────────
304	
305	message SubmitReportsRequest {
306	  string session_id = 1;
307	  repeated EyeReport reports = 2;
308	}
309	
310	message EyeReport {
311	  string eye_name = 1;         // dom_reader, vision, page_diff, goal_verifier, error_detector
312	  int64 timestamp = 2;
313	  float confidence = 3;
314	  float goal_relevance = 4;
315	  oneof content {
316	    DomReportContent dom = 10;
317	    VisionReportContent vision = 11;
318	    DiffReportContent diff = 12;
319	    VerificationContent verification = 13;
320	    ErrorReportContent error = 14;
321	  }
322	}
323	
324	message DomReportContent {
325	  DistilledDom dom = 1;
326	  repeated InteractiveElement focused_elements = 2;
327	}
328	
329	message VisionReportContent {
330	  repeated string visible_elements = 1;
331	  repeated string overlays = 2;
332	  repeated string blocked_regions = 3;
333	  string page_type = 4;
334	  repeated string anomalies = 5;
335	  string raw_response = 6;
336	}
337	
338	message DiffReportContent {
339	  DiffReport diff = 1;
340	}
341	
342	message VerificationContent {
343	  bool sub_goal_advanced = 1;
344	  float confidence = 2;
345	  string reasoning = 3;
346	  string criteria_status = 4;  // pending, met, failed, partial
347	}
348	
349	message ErrorReportContent {
350	  string failure_type = 1;     // silent_fail, wrong_element, blocked_interaction, state_mismatch, goal_drift, timeout, navigation_error
351	  string description = 2;
352	  repeated string recovery_actions = 3;
353	  bool should_retry = 4;
354	  int32 max_retries = 5;
355	}
356	
357	// ────────────────────────────────────────────────────────────
358	// Signal Routing
359	// ────────────────────────────────────────────────────────────
360	
361	message RoutedSignal {
362	  string unified_perception = 1;       // natural language summary for Decision layer
363	  repeated DistractionAlert alerts = 2;
364	  float confidence = 3;
365	  string recommended_action_hint = 4;
366	  repeated string contradictions = 5;  // cross-eye contradictions detected
367	}
368	
369	message DistractionAlert {
370	  string kind = 1;
371	  string description = 2;
372	  string action_taken = 3;
373	}
374	
375	// ────────────────────────────────────────────────────────────
376	// Goal State
377	// ────────────────────────────────────────────────────────────
378	
379	message CreateGoalRequest {
380	  string description = 1;
381	  map<string, string> context = 2;
382	  int32 max_budget_cents = 3;
383	  int32 max_steps = 4;
384	}
385	
386	message GoalState {
387	  string goal_id = 1;
388	  string description = 2;
389	  string status = 3;           // pending, active, completed, failed, blocked
390	  float progress = 4;          // 0.0 to 1.0
391	  repeated SubGoal sub_goals = 5;
392	  GoalContext context = 6;
393	  int64 created_at = 7;
394	  int64 updated_at = 8;
395	}
396	
397	message SubGoal {
398	  string id = 1;
399	  string description = 2;
400	  repeated string success_criteria = 3;
401	  repeated string depends_on = 4;
402	  string status = 5;           // pending, active, done, blocked
403	}
404	
405	message GoalContext {
406	  string current_url = 1;
407	  string last_action = 2;
408	  string last_observation = 3;
409	  repeated float intent_embedding = 4;
410	  uint32 distraction_count = 5;
411	}
412	
413	message GoalStateRequest {
414	  string goal_id = 1;
415	}
416	
417	message ProgressUpdate {
418	  string goal_id = 1;
419	  float progress = 2;
420	  string status = 3;
421	  repeated SubGoal sub_goals = 4;
422	}
423	
424	message GoalUpdate {
425	  string goal_id = 1;
426	  string event_type = 2;       // progress, sub_goal_completed, blocked, failed, budget_warning
427	  string message = 3;
428	  float progress = 4;
429	  SubGoal sub_goal = 5;
430	}
431	
432	// ────────────────────────────────────────────────────────────
433	// Decision Intelligence
434	// ────────────────────────────────────────────────────────────
435	
436	message StoreScoreRequest {
437	  string session_id = 1;
438	  string goal_id = 2;
439	  Action action = 3;
440	  string tool = 4;
441	  repeated float context_embedding = 5;
442	  float outcome_score = 6;     // immediate: did action succeed?
443	  float result_score = 7;      // immediate: what was produced?
444	  string error_message = 8;
445	  float error_penalty = 9;
446	  float business_outcome = 10; // composite of immediate + short-term + long-term
447	  string context_type = 11;    // task type for grouping
448	}
449	
450	message StoreScoreResponse {
451	  string record_id = 1;
452	  int64 total_records = 2;
453	}
454	
455	message QueryBestActionsRequest {
456	  repeated float context_embedding = 1;
457	  int32 k = 2;
458	  float min_score = 3;
459	  string context_type = 4;
460	}
461	
462	message SearchRequest {
463	  repeated float context_embedding = 1;
464	  int32 k = 2;
465	  float min_score = 3;
466	  string context_type = 4;
467	}
468	
469	message ScoredActionList {
470	  repeated ScoredAction actions = 1;
471	  int64 search_time_us = 2;
472	}
473	
474	message ScoredAction {
475	  Action action = 1;
476	  string tool = 2;
477	  float composite_score = 3;
478	  float outcome_score = 4;
479	  float result_score = 5;
480	  float error_penalty = 6;
481	  float business_outcome = 7;
482	  uint32 use_count = 8;
483	  int64 last_used_at = 9;
484	}
485	
486	// ────────────────────────────────────────────────────────────
487	// Budget & Cost Tracking
488	// ────────────────────────────────────────────────────────────
489	
490	message BudgetStatusRequest {
491	  string goal_id = 1;          // empty = global status
492	}
493	
494	message BudgetStatus {
495	  string mode = 1;             // normal, conservative, critical, emergency
496	  int32 budget_cents = 2;
497	  int32 spent_cents = 3;
498	  float remaining_pct = 4;
499	  int32 daily_spend_limit_cents = 5;
500	  int32 daily_spent_cents = 6;
501	}
502	
503	message BudgetConfigRequest {
504	  int32 default_per_goal_cents = 1;
505	  int32 daily_api_key_spend_limit_cents = 2;
506	  float normal_threshold_pct = 3;
507	  float conservative_threshold_pct = 4;
508	  float critical_threshold_pct = 5;
509	}
510	
511	message BudgetConfig {
512	  int32 default_per_goal_cents = 1;
513	  int32 daily_api_key_spend_limit_cents = 2;
514	  float normal_threshold_pct = 3;
515	  float conservative_threshold_pct = 4;
516	  float critical_threshold_pct = 5;
517	}
518	
519	// ────────────────────────────────────────────────────────────
520	// Health
521	// ────────────────────────────────────────────────────────────
522	
523	message HealthStatus {
524	  bool healthy = 1;
525	  string version = 2;
526	  int32 active_sessions = 3;
527	  int32 active_goals = 4;
528	  int64 uptime_seconds = 5;
529	  int64 total_actions_executed = 6;
530	  int64 total_decisions_stored = 7;
531	  string budget_mode = 8;
532	  map<string, string> metrics = 9;
533	}
