152	    async fn create_session(
153	        &self,
154	        request: Request<CreateSessionRequest>,
155	    ) -> Result<Response<Session>, Status> {
156	        let req = request.into_inner();
157	        let goal_id = parse_uuid(&req.goal_id, "goal_id")?;
158	        let start_url = optional_string(&req.start_url);
159	
160	        let session_id = self
161	            .sessions
162	            .create(goal_id, start_url)
163	            .await
164	            .map_err(|e| Status::internal(e.to_string()))?;
165	
166	        let now = now_epoch_ms();
167	        self.metrics.inc_sessions(1);
168	
169	        Ok(Response::new(Session {
170	            session_id: session_id.to_string(),
171	            goal_id: req.goal_id,
172	            status: "idle".into(),
173	            current_page: None,
174	            created_at: now,
175	            last_activity_at: now,
176	        }))
177	    }
