181	        request: Request<CloseSessionRequest>,
182	    ) -> Result<Response<Empty>, Status> {
183	        let req = request.into_inner();
184	        let session_id = parse_uuid(&req.session_id, "session_id")?;
185	        self.sessions
186	            .close(session_id)
187	            .await
188	            .map_err(|e| Status::internal(e.to_string()))?;
