216	    async fn execute_action(
217	        &self,
218	        request: Request<ExecuteActionRequest>,
219	    ) -> Result<Response<ActionResult>, Status> {
220	        let req = request.into_inner();
221	        let session_id = parse_uuid(&req.session_id, "session_id")?;
222	
223	        let proto_action = req
224	            .action
225	            .ok_or_else(|| Status::invalid_argument("action is required"))?;
226	
