540	    async fn classify_distractions(
541	        &self,
542	        request: Request<DistractionRequest>,
543	    ) -> Result<Response<DistractionList>, Status> {
544	        let req = request.into_inner();
545	        let url = req.url;
546	
547	        // Extract CSS class/id hints from DOM elements for distraction pattern matching
548	        let css_hints = req
549	            .dom
550	            .as_ref()
551	            .map(|dom| {
552	                dom.elements
553	                    .iter()
554	                    .flat_map(|el| {
555	                        el.attributes
556	                            .iter()
557	                            .filter(|(k, _)| *k == "class" || *k == "id")
558	                            .map(|(_, v)| v.clone())
559	                    })
560	                    .collect::<Vec<_>>()
561	                    .join(" ")
562	            })
563	            .unwrap_or_default();
564	
565	        // Extract all visible text from the distilled DOM for content scanning
566	        let dom_text = req
567	            .dom
568	            .as_ref()
569	            .map(|dom| {
570	                dom.elements
571	                    .iter()
572	                    .map(|el| el.text.as_str())
573	                    .collect::<Vec<_>>()
574	                    .join(" ")
575	            })
576	            .unwrap_or_default();
577	
578	        self.metrics.inc_immune_scans();
579	        let classifier = ans_immune::DistractionClassifier;
580	        let flags = classifier.classify(&url, &dom_text, &css_hints);
581	
582	        let distractions: Vec<_> = flags
583	            .iter()
584	            .map(ans_immune::serialization::distraction_to_proto_list_item)
585	            .collect();
586	
587	        Ok(Response::new(DistractionList {
588	            distractions,
589	            classification_time_us: 0,
590	        }))
591	    }
