841	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
842	/// Returns `None` if the `eye_name` is unrecognized or the content is missing.
843	fn proto_to_core_eye_report(
844	    proto: &ans_proto::ans::EyeReport,
845	) -> Option<ans_core::signal::EyeReport> {
846	    use ans_proto::ans::eye_report::Content;
847	
848	    let eye_name = match proto.eye_name.as_str() {
849	        "dom_reader" => EyeName::DomReader,
850	        "vision" => EyeName::Vision,
851	        "page_diff" => EyeName::PageDiff,
852	        "goal_verifier" => EyeName::GoalVerifier,
853	        "error_detector" => EyeName::ErrorDetector,
854	        _ => return None,
855	    };
856	
857	    let content = match &proto.content {
858	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
859	            elements: vec![],
860	            interactive: vec![],
861	            mode: dom
862	                .dom
863	                .as_ref()
864	                .map_or(DistillMode::AllFields, |d| match d.mode.as_str() {
865	                    "text_only" => DistillMode::TextOnly,
866	                    "input_fields" => DistillMode::InputFields,
867	                    _ => DistillMode::AllFields,
868	                }),
869	        },
870	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
871	            visible_elements: v.visible_elements.clone(),
872	            overlays: v.overlays.clone(),
873	            blocked_regions: v.blocked_regions.clone(),
874	            page_type: v.page_type.clone(),
875	            anomalies: v.anomalies.clone(),
876	            raw_response: v.raw_response.clone(),
877	        },
878	        Some(Content::Diff(d)) => {
879	            let diff_report = d.diff.as_ref();
880	            EyeReportContent::DiffReport {
881	                added: diff_report.map_or(vec![], |r| {
882	                    r.added.iter().map(|e| e.selector.clone()).collect()
883	                }),
884	                removed: diff_report.map_or(vec![], |r| {
885	                    r.removed.iter().map(|e| e.selector.clone()).collect()
886	                }),
887	                modified: diff_report.map_or(vec![], |r| {
888	                    r.modified.iter().map(|m| m.selector.clone()).collect()
889	                }),
890	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
891	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
892	            }
893	        }
894	        Some(Content::Verification(v)) => EyeReportContent::Verification {
895	            sub_goal_advanced: v.criteria_status == "met",
896	            confidence: v.confidence,
897	            reasoning: v.reasoning.clone(),
898	            criteria_status: v.criteria_status.clone(),
899	        },
900	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
901	            failure_type: e.failure_type.clone(),
902	            description: e.description.clone(),
903	            recovery_actions: e.recovery_actions.clone(),
904	            should_retry: e.should_retry,
905	            max_retries: e.max_retries as u32,
906	        },
907	        None => return None,
908	    };
909	
910	    Some(ans_core::signal::EyeReport {
911	        eye_name,
912	        timestamp: chrono::Utc::now(),
913	        confidence: proto.confidence,
914	        goal_relevance: proto.goal_relevance,
915	        content,
916	    })
917	}
918	
919	/// Format the oneof eye report content into a readable string.
920	fn format_eye_content(content: Option<&ans_proto::ans::eye_report::Content>) -> String {
921	    use ans_proto::ans::eye_report::Content;
922	    match content {
923	        Some(Content::Dom(dom)) => {
924	            format!(
925	                "DOM: {} elements, {} interactive",
926	                dom.dom.as_ref().map_or(0, |d| d.elements.len() as i32),
927	                dom.focused_elements.len()
928	            )
929	        }
930	        Some(Content::Vision(v)) => {
931	            format!(
932	                "Vision: {} visible, {} overlays, type={}",
933	                v.visible_elements.len(),
934	                v.overlays.len(),
935	                v.page_type
936	            )
937	        }
938	        Some(Content::Diff(d)) => {
939	            format!(
940	                "Diff: {}% visual change",
941	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
942	            )
943	        }
944	        Some(Content::Verification(v)) => {
945	            format!(
946	                "Verify: {} (confidence={:.0}%)",
947	                v.criteria_status,
948	                v.confidence * 100.0
949	            )
950	        }
951	        Some(Content::Error(e)) => {
952	            format!("Error: {} — {}", e.failure_type, e.description)
953	        }
954	        None => "no content".into(),
955	    }
956	}
