1	//! Budget tracker — per-goal and global (per-API-key) spend tracking.
2	//!
3	//! Before any LLM/Vision API call, the tracker:
4	//! 1. Checks remaining budget → updates circuit breaker mode
5	//! 2. If mode disallows the call → returns cached/fallback response
6	//! 3. If allowed → tracks actual token usage from API response
7	//! 4. Updates spend counters
8	
9	use crate::circuit_breaker::CircuitBreaker;
10	use ans_core::budget::BudgetMode;
11	
12	/// Global budget configuration.
13	#[derive(Debug, Clone)]
14	pub struct BudgetConfig {
15	    pub default_per_goal_cents: u32,
16	    pub daily_spend_limit_cents: u32,
17	    pub normal_threshold_pct: f32,
18	    pub conservative_threshold_pct: f32,
19	    pub critical_threshold_pct: f32,
20	}
21	
22	impl Default for BudgetConfig {
23	    fn default() -> Self {
24	        Self {
25	            default_per_goal_cents: 500,
26	            daily_spend_limit_cents: 5000,
27	            normal_threshold_pct: 20.0,
28	            conservative_threshold_pct: 10.0,
29	            critical_threshold_pct: 5.0,
30	        }
31	    }
32	}
33	
34	/// Thread-safe global budget tracker.
35	///
36	/// Tracks spend across all goals for a single API key. Circuit breaker
37	/// tightens as daily budget is consumed. Per-goal trackers are created
38	/// on demand with their own budget caps.
39	pub struct BudgetTracker {
40	    config: BudgetConfig,
41	    breaker: CircuitBreaker,
42	    /// Total spent today across all goals.
43	    daily_spent_cents: u32,
44	    /// Total spent since tracker creation.
45	    total_spent_cents: u32,
46	}
47	
48	impl BudgetTracker {
49	    #[must_use] 
50	    pub fn new(config: BudgetConfig) -> Self {
51	        Self {
52	            config,
53	            breaker: CircuitBreaker::new(),
54	            daily_spent_cents: 0,
55	            total_spent_cents: 0,
56	        }
57	    }
58	
59	    /// Current budget mode based on daily spend vs daily limit.
60	    #[must_use] 
61	    pub fn mode(&self) -> BudgetMode {
62	        self.breaker.current_mode()
63	    }
64	
65	    /// Remaining daily budget percentage.
66	    #[must_use] 
67	    pub fn remaining_pct(&self) -> f32 {
68	        if self.config.daily_spend_limit_cents == 0 {
69	            return 0.0;
70	        }
71	        let remaining = self
72	            .config
73	            .daily_spend_limit_cents
74	            .saturating_sub(self.daily_spent_cents);
75	        (remaining as f32 / self.config.daily_spend_limit_cents as f32) * 100.0
76	    }
77	
78	    /// Track spend against the daily budget. Updates circuit breaker.
79	    pub fn track_spend(&mut self, cost_cents: u32) {
80	        self.daily_spent_cents = self.daily_spent_cents.saturating_add(cost_cents);
81	        self.total_spent_cents = self.total_spent_cents.saturating_add(cost_cents);
82	        self.breaker.update(self.remaining_pct());
83	    }
84	
85	    /// Get the full budget status snapshot.
86	    #[must_use] 
87	    pub fn status(&self) -> BudgetStatus {
88	        BudgetStatus {
89	            mode: self.mode(),
90	            budget_cents: self.config.daily_spend_limit_cents,
91	            spent_cents: self.total_spent_cents,
92	            remaining_pct: self.remaining_pct(),
93	            daily_spend_limit_cents: self.config.daily_spend_limit_cents,
94	            daily_spent_cents: self.daily_spent_cents,
95	        }
96	    }
97	
98	    /// Update the budget configuration. Resets circuit breaker
99	    /// if the daily limit was increased.
100	    pub fn configure(&mut self, config: BudgetConfig) {
101	        let limit_increased = config.daily_spend_limit_cents > self.config.daily_spend_limit_cents;
102	        self.config = config;
103	        if limit_increased {
104	            self.breaker = CircuitBreaker::new();
105	            self.breaker.update(self.remaining_pct());
106	        }
107	    }
108	
109	    /// Current config, for serialization.
110	    #[must_use] 
111	    pub const fn config(&self) -> &BudgetConfig {
112	        &self.config
113	    }
114	}
115	
116	/// Snapshot of budget state.
117	#[derive(Debug, Clone)]
118	pub struct BudgetStatus {
119	    pub mode: BudgetMode,
120	    pub budget_cents: u32,
121	    pub spent_cents: u32,
122	    pub remaining_pct: f32,
123	    pub daily_spend_limit_cents: u32,
124	    pub daily_spent_cents: u32,
125	}
126	
127	impl Default for BudgetTracker {
128	    fn default() -> Self {
129	        Self::new(BudgetConfig::default())
130	    }
131	}
132	
133	#[cfg(test)]
134	mod tests {
135	    use super::*;
136	
137	    #[test]
138	    fn test_normal_mode_at_full_budget() {
139	        let tracker = BudgetTracker::new(BudgetConfig::default());
140	        assert_eq!(tracker.mode(), BudgetMode::Normal);
141	        assert!(tracker.remaining_pct() > 90.0);
142	    }
143	
144	    #[test]
145	    fn test_mode_transitions_on_spend() {
146	        let config = BudgetConfig {
147	            daily_spend_limit_cents: 100,
148	            ..Default::default()
149	        };
150	        let mut tracker = BudgetTracker::new(config);
151	
152	        // Spend 88 → 12% remaining → Conservative (10-20%)
153	        tracker.track_spend(88);
154	        assert_eq!(tracker.mode(), BudgetMode::Conservative);
155	
156	        // Spend 96 → 4% remaining → Emergency (<5%)
157	        tracker.track_spend(96);
158	        assert_eq!(tracker.mode(), BudgetMode::Emergency);
159	    }
160	
161	    #[test]
162	    fn test_configure_resets_on_limit_increase() {
163	        let mut tracker = BudgetTracker::new(BudgetConfig::default());
164	        tracker.track_spend(4900); // almost all of 5000
165	        assert_eq!(tracker.mode(), BudgetMode::Emergency);
166	
167	        tracker.configure(BudgetConfig {
168	            daily_spend_limit_cents: 10000,
169	            ..Default::default()
170	        });
171	        assert_eq!(tracker.mode(), BudgetMode::Normal);
172	    }
173	
174	    #[test]
175	    fn test_status_snapshot() {
176	        let tracker = BudgetTracker::new(BudgetConfig::default());
177	        let status = tracker.status();
178	        assert_eq!(status.mode, BudgetMode::Normal);
179	        assert_eq!(status.spent_cents, 0);
180	    }
181	}
