1	//! Signal router — the central nervous system hub.
2	//!
3	//! Receives `EyeReports` from all 5 eyes, scores goal relevance,
4	//! suppresses noise, resolves contradictions, and emits a unified
5	//! `RoutedSignal` to the Decision Intelligence Layer.
6	//!
7	//! Pipeline:
8	//! 1. Score each report for goal relevance
9	//! 2. Filter out noise (relevance below threshold)
10	//! 3. Amplify high-relevance signals
11	//! 4. Resolve cross-eye contradictions
12	//! 5. Synthesize unified `RoutedSignal`
13	
14	use std::fmt::Write;
15	
16	use ans_core::signal::{DistractionAlert, EyeName, EyeReport, EyeReportContent, RoutedSignal};
17	
18	use crate::contradiction::ContradictionResolver;
19	
20	/// Minimum relevance score for a report to pass noise suppression.
21	const NOISE_THRESHOLD: f32 = 0.15;
22	
23	/// Eye-specific base weight for relevance scoring.
24	const fn eye_weight(eye: EyeName) -> f32 {
25	    match eye {
26	        EyeName::GoalVerifier => 0.35,
27	        EyeName::PageDiff => 0.25,
28	        EyeName::DomReader => 0.20,
29	        EyeName::Vision => 0.15,
30	        EyeName::ErrorDetector => 0.05,
31	    }
32	}
33	
34	/// The signal router. Single instance per daemon, shared across sessions.
35	pub struct SignalRouter {
36	    resolver: ContradictionResolver,
37	}
38	
39	impl SignalRouter {
40	    #[must_use] 
41	    pub const fn new() -> Self {
42	        Self {
43	            resolver: ContradictionResolver,
44	        }
45	    }
46	
47	    /// Route a batch of eye reports into a unified signal.
48	    pub fn route(&self, reports: &[EyeReport]) -> RoutedSignal {
49	        if reports.is_empty() {
50	            return RoutedSignal {
51	                unified_perception: String::new(),
52	                alerts: Vec::new(),
53	                confidence: 0.0,
54	                recommended_action_hint: None,
55	                contradictions: Vec::new(),
56	            };
57	        }
58	
59	        // 1. Score and filter
60	        let scored: Vec<ScoredReport<'_>> = reports
61	            .iter()
62	            .map(|r| ScoredReport {
63	                report: r,
64	                relevance: compute_relevance(r),
65	            })
66	            .collect();
67	
68	        // 2. Suppress noise
69	        let active: Vec<&ScoredReport<'_>> = scored
70	            .iter()
71	            .filter(|s| s.relevance >= NOISE_THRESHOLD)
72	            .collect();
73	
74	        let reports_for_resolution: Vec<EyeReport> = if active.is_empty() {
75	            // Everything was noise — keep the highest-relevance one as fallback
76	            scored
77	                .iter()
78	                .max_by(|a, b| a.relevance.partial_cmp(&b.relevance).unwrap_or(std::cmp::Ordering::Equal))
79	                .map(|s| s.report.clone())
80	                .into_iter()
81	                .collect()
82	        } else {
83	            active.iter().map(|s| s.report.clone()).collect()
84	        };
85	
86	        // 3. Resolve contradictions
87	        let contradictions = self.resolver.resolve_all(&reports_for_resolution);
88	
89	        // 4. Synthesize unified perception
90	        let parts: Vec<String> = reports_for_resolution
91	            .iter()
92	            .map(format_eye_summary)
93	            .collect();
94	
95	        let unified_perception = parts.join(" | ");
96	
97	        // 5. Compute aggregate confidence
98	        let confidence = if reports_for_resolution.is_empty() {
99	            0.0
100	        } else {
101	            let total: f32 = reports_for_resolution
102	                .iter()
103	                .map(|r| r.confidence * eye_weight(r.eye_name))
104	                .sum();
105	            let max_possible: f32 = reports_for_resolution
106	                .iter()
107	                .map(|r| eye_weight(r.eye_name))
108	                .sum();
109	            if max_possible > 0.0 {
110	                (total / max_possible).clamp(0.0, 1.0)
111	            } else {
112	                0.0
113	            }
114	        };
115	
116	        // 6. Generate action hint
117	        let hint = generate_hint(&reports_for_resolution, &contradictions);
118	
119	        // 7. Collect alerts from error reports
120	        let alerts = collect_alerts(&reports_for_resolution);
121	
122	        RoutedSignal {
123	            unified_perception,
124	            alerts,
125	            confidence,
126	            recommended_action_hint: hint,
127	            contradictions,
128	        }
129	    }
130	}
