1	//! Decision record CRUD and vector search.
2	//!
3	//! In-memory store with cosine similarity search. `LanceDB` integration
4	//! with `IVF_PQ` index is deferred to a future phase when Arrow/Lance
5	//! columnar storage is fully wired.
6	
7	use std::sync::RwLock;
8	
9	use ans_core::decision::DecisionRecord;
10	
11	/// Thread-safe in-memory decision store with vector similarity search.
12	pub struct DecisionStore {
13	    records: RwLock<Vec<DecisionRecord>>,
14	}
15	
16	impl DecisionStore {
17	    /// Create a new empty decision store.
18	    #[must_use] 
19	    pub const fn new() -> Self {
20	        Self {
21	            records: RwLock::new(Vec::new()),
22	        }
23	    }
24	
25	    /// Insert a decision record. Returns the total count after insert.
26	    pub fn insert(&self, record: DecisionRecord) -> usize {
27	        let mut records = self.records.write().unwrap_or_else(std::sync::PoisonError::into_inner);
28	        records.push(record);
29	        records.len()
30	    }
31	
32	    /// Total number of stored records.
33	    pub fn len(&self) -> usize {
34	        self.records.read().unwrap_or_else(std::sync::PoisonError::into_inner).len()
35	    }
36	
37	    /// Whether the store is empty.
38	    pub fn is_empty(&self) -> bool {
39	        self.len() == 0
40	    }
41	
42	    /// Query top-k decisions by cosine similarity to the given embedding.
43	    /// Returns records sorted by similarity descending, filtered by `min_score`.
44	    pub fn query_similar(
45	        &self,
46	        embedding: &[f32],
47	        k: usize,
48	        min_score: f32,
49	    ) -> Vec<(DecisionRecord, f32)> {
50	        let records = self.records.read().unwrap_or_else(std::sync::PoisonError::into_inner);
51	        if records.is_empty() {
52	            return Vec::new();
53	        }
54	
55	        let mut scored: Vec<(usize, f32)> = records
56	            .iter()
57	            .enumerate()
58	            .filter_map(|(i, r)| {
59	                let sim = cosine_similarity(embedding, &r.context_embedding);
60	                if sim >= min_score {
61	                    Some((i, sim))
62	                } else {
63	                    None
64	                }
65	            })
66	            .collect();
67	
68	        // Sort descending by similarity
69	        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
70	
71	        scored
72	            .into_iter()
73	            .take(k)
74	            .map(|(i, sim)| (records[i].clone(), sim))
75	            .collect()
76	    }
77	}
78	
79	impl Default for DecisionStore {
80	    fn default() -> Self {
81	        Self::new()
82	    }
83	}
84	
85	/// Cosine similarity between two vectors.
86	fn cosine_similarity(a: &[f32], b: &[f32]) -> f32 {
87	    if a.is_empty() || b.is_empty() {
88	        return 0.0;
89	    }
90	
91	    let min_len = a.len().min(b.len());
92	    let mut dot = 0.0f32;
93	    let mut norm_a = 0.0f32;
94	    let mut norm_b = 0.0f32;
95	
96	    for i in 0..min_len {
97	        dot += a[i] * b[i];
98	        norm_a += a[i] * a[i];
99	        norm_b += b[i] * b[i];
100	    }
101	
102	    // Add remaining squared terms for the longer vector's norm
103	    for v in a.iter().skip(min_len) {
104	        norm_a += v * v;
105	    }
106	    for v in b.iter().skip(min_len) {
107	        norm_b += v * v;
108	    }
109	
110	    let denom = (norm_a.sqrt() * norm_b.sqrt()).max(f32::EPSILON);
111	    dot / denom
112	}
